    { id: 9, name: 'CSS Grid Layout Mastery', category: 'frontend' },
    { id: 10, name: 'Machine Learning with Python', category: 'data' },
];

// Custom debounce hook. Returns the debounced value plus a `pending`
// flag that is true while we're waiting out the delay.
function useDebounce(value, delay) {
    const [debouncedValue, setDebouncedValue] = useState(value);
    const [pending, setPending] = useState(false);
    const timeoutRef = useRef(null);

    useEffect(() => {
        // If the value already matches, there's nothing to wait for.
        if (value === debouncedValue) {
            setPending(false);
            return;
        }

        setPending(true);
        timeoutRef.current = setTimeout(() => {
            setDebouncedValue(value);
            setPending(false);
        }, delay);

        // Cleanup: clear the pending timeout whenever `value` changes
        // again or the component unmounts (req. 8 — no memory leaks).
        return () => clearTimeout(timeoutRef.current);
    }, [value, delay, debouncedValue]);

    return [debouncedValue, pending];
