    const [debouncedQuery, isPending] = useDebounce(query, 300);

    // Treat whitespace-only input as empty (req. 9 + req. 5).
    const trimmedQuery = debouncedQuery.trim();

    const filteredItems = useMemo(() => {
        if (!trimmedQuery) return ITEMS;
        const needle = trimmedQuery.toLowerCase();
        return ITEMS.filter(item =>
            item.name.toLowerCase().includes(needle)
        );
    }, [trimmedQuery]);

    // Only show the searching indicator when there's something to search for.
    const showSearching = isPending && query.trim().length > 0;

    return (
        <div>
            <h2>Resources</h2>

            <input
                type="text"
                value={query}
                onChange={e => setQuery(e.target.value)}
                placeholder="Search resources..."
                aria-label="Search resources"
            />

            {showSearching && <p aria-live="polite">Searching...</p>}

            {!showSearching && filteredItems.length === 0 ? (
                <p>No results found</p>
            ) : (
                <ul>
                    {filteredItems.map(item => (
                        <li key={item.id}>
                            <strong>{highlightMatch(item.name, trimmedQuery)}</strong>{' '}
                            <span>({item.category})</span>
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
}

export default ResourceList;
